import csv

questions = [
  {"id":"4009","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Inequacoes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O conjunto solucao da inequacao 2x - 3 > 7 e:","alternativa_a":"x > 5","alternativa_b":"x < 5","alternativa_c":"x > 2","alternativa_d":"x >= 5","alternativa_e":"x < 2","resposta_correta":"a","explicacao":"2x - 3 > 7 => 2x > 10 => x > 5.","resposta":""},
  {"id":"4010","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Dominio e imagem","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O dominio da funcao f(x) = raiz(x-2) e:","alternativa_a":"x >= 2","alternativa_b":"x > 2","alternativa_c":"x <= 2","alternativa_d":"todos os reais","alternativa_e":"x >= 0","resposta_correta":"a","explicacao":"Para a raiz quadrada ser definida nos reais, o radicando deve ser nao negativo: x - 2 >= 0, logo x >= 2.","resposta":""},
  {"id":"4011","tipo":"multipla","disciplina":"Matematica","tema":"Trigonometria","subtema":"Seno e cosseno","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O valor de sen(30 graus) e:","alternativa_a":"1/2","alternativa_b":"raiz(3)/2","alternativa_c":"raiz(2)/2","alternativa_d":"1","alternativa_e":"0","resposta_correta":"a","explicacao":"Os valores trigonometricos basicos: sen(30) = 1/2, cos(30) = raiz(3)/2, tan(30) = raiz(3)/3.","resposta":""},
  {"id":"4012","tipo":"multipla","disciplina":"Matematica","tema":"Calculo","subtema":"Derivadas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A derivada de f(x) = x3 - 2x + 5 e:","alternativa_a":"3x2 - 2","alternativa_b":"3x2 + 2","alternativa_c":"x2 - 2","alternativa_d":"3x - 2","alternativa_e":"x3 - 2","resposta_correta":"a","explicacao":"Pela regra da potencia: d/dx(xn) = n*x^(n-1). f'(x) = 3x2 - 2 + 0 = 3x2 - 2.","resposta":""},
  {"id":"4013","tipo":"multipla","disciplina":"Matematica","tema":"Calculo","subtema":"Integrais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A integral de 2x dx e:","alternativa_a":"x2 + C","alternativa_b":"2x2 + C","alternativa_c":"x + C","alternativa_d":"2 + C","alternativa_e":"x2/2 + C","resposta_correta":"a","explicacao":"Integral(2x dx) = 2 * x2/2 + C = x2 + C.","resposta":""},
  {"id":"4014","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Gravitacao universal","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Pela Lei de Gravitacao Universal de Newton, a forca entre dois corpos e proporcional ao produto de suas massas e:","alternativa_a":"Inversamente proporcional ao quadrado da distancia entre eles","alternativa_b":"Diretamente proporcional a distancia","alternativa_c":"Inversamente proporcional a distancia","alternativa_d":"Proporcional ao cubo da distancia","alternativa_e":"Independente da distancia","resposta_correta":"a","explicacao":"F = G * m1 * m2 / r2. A forca gravitacional e proporcional ao produto das massas e inversamente proporcional ao quadrado da distancia. G = 6,67 x 10-11 N.m2/kg2 e a constante gravitacional universal.","resposta":""},
  {"id":"4015","tipo":"multipla","disciplina":"Fisica","tema":"Optica","subtema":"Lentes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma lente convergente tem foco em 20 cm. Um objeto a 60 cm da lente forma uma imagem a que distancia?","alternativa_a":"30 cm","alternativa_b":"20 cm","alternativa_c":"60 cm","alternativa_d":"40 cm","alternativa_e":"15 cm","resposta_correta":"a","explicacao":"1/f = 1/p + 1/p' => 1/20 = 1/60 + 1/p' => 1/p' = 1/20 - 1/60 = 3/60 - 1/60 = 2/60 => p' = 30 cm.","resposta":""},
  {"id":"4016","tipo":"multipla","disciplina":"Fisica","tema":"Fisica Moderna","subtema":"Radioatividade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Na emissao alfa, o nucleo atomico perde:","alternativa_a":"2 protons e 2 neutrons (particula alfa = nucleo de helio)","alternativa_b":"1 eletron","alternativa_c":"1 proton","alternativa_d":"1 neutron","alternativa_e":"1 foton","resposta_correta":"a","explicacao":"A particula alfa (radiacao alfa) e identica ao nucleo do atomo de helio-4: 2 protons + 2 neutrons. Ao emiti-la, o nucleo perde numero atomico Z-2 e numero de massa A-4. E a menos penetrante das radiacoes, mas altamente ionizante.","resposta":""},
  {"id":"4017","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Capacitores","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um capacitor de 100 microfarads e carregado com tensao de 10 V. A energia armazenada e:","alternativa_a":"5 mJ","alternativa_b":"1 mJ","alternativa_c":"10 mJ","alternativa_d":"100 mJ","alternativa_e":"0,5 mJ","resposta_correta":"a","explicacao":"E = C*V2/2 = (100x10^-6 * 100)/2 = 10^-2/2 = 5x10^-3 J = 5 mJ.","resposta":""},
  {"id":"4018","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Gases ideais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Na lei dos gases ideais PV = nRT, o 'R' representa:","alternativa_a":"A constante universal dos gases (8,314 J/mol.K)","alternativa_b":"A resistencia do gas","alternativa_c":"A raiz quadrada da temperatura","alternativa_d":"A razao entre pressao e volume","alternativa_e":"A relacao entre o numero de atomos e moleculas","resposta_correta":"a","explicacao":"R e a constante universal dos gases = 8,314 J/(mol.K) = 0,082 atm.L/(mol.K). A equacao de Clapeyron PV = nRT relaciona pressao (P), volume (V), numero de mols (n), constante R e temperatura absoluta T (em Kelvin).","resposta":""},
  {"id":"4019","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Equilibrio quimico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Segundo o Principio de Le Chatelier, ao aumentar a pressao num sistema gasoso em equilibrio, o equilibrio se deslocara:","alternativa_a":"No sentido de menor numero de mols de gas","alternativa_b":"No sentido de maior numero de mols de gas","alternativa_c":"Nao se altera com a pressao","alternativa_d":"Sempre para a esquerda","alternativa_e":"Sempre para a direita","resposta_correta":"a","explicacao":"Pelo Principio de Le Chatelier: um sistema em equilibrio perturbado tende a minimizar a perturbacao. Ao aumentar a pressao, o sistema desloca-se para o lado com menor numero de mols gasosos, reduzindo a pressao. Se os lados tem igual numero de mols gasosos, a pressao nao afeta o equilibrio.","resposta":""},
  {"id":"4020","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Proteinas e aminoacidos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As proteinas sao polimeros formados pela uniao de:","alternativa_a":"Aminoacidos, por ligacoes peptidicas","alternativa_b":"Nucleotideos, por ligacoes fosfodiestera","alternativa_c":"Acidos graxos e glicerol","alternativa_d":"Monossacarideos, por ligacoes glicosidicas","alternativa_e":"Bases nitrogenadas e fosfatos","resposta_correta":"a","explicacao":"As proteinas sao macromoleculas formadas por cadeias de aminoacidos ligados por ligacoes peptidicas (ligacao amida entre o grupo carboxila de um aminoacido e o grupo amino do proximo, com perda de agua). Existem 20 aminoacidos naturais que combinados formam a enorme diversidade de proteinas.","resposta":""},
  {"id":"4021","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Acidos carboxilicos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O grupo funcional dos acidos carboxilicos e:","alternativa_a":"-COOH (carboxila)","alternativa_b":"-OH (hidroxila)","alternativa_c":"-CHO (aldeido)","alternativa_d":"-CO- (carbonila)","alternativa_e":"-NH2 (amina)","resposta_correta":"a","explicacao":"Os acidos carboxilicos contem o grupo funcional carboxila (-COOH), que e a combinacao de carbonila (C=O) e hidroxila (-OH). Exemplos: acido acetico (CH3COOH), acido formico (HCOOH), acido acetoamilico (acido salicilico). Sao acidos fracos em solucao aquosa.","resposta":""},
  {"id":"4022","tipo":"multipla","disciplina":"Biologia","tema":"Microbiologia","subtema":"Bacterias e virus","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Qual a principal diferenca entre bacterias e virus?","alternativa_a":"Bacterias sao celulas procariontes; virus nao sao celulas e so se replicam em celulas hospedeiras","alternativa_b":"Virus sao maiores que bacterias","alternativa_c":"Bacterias nao possuem material genetico","alternativa_d":"Virus possuem parede celular","alternativa_e":"Bacterias so se reproduzem em celulas hospedeiras","resposta_correta":"a","explicacao":"Bacterias sao organismos unicelulares procariontes (sem nucleo membranado), com metabolismo proprio e capacidade de se reproduzir autonomamente. Virus nao sao celulas: sao agentes aceulares compostos de acido nucleico (DNA ou RNA) envolto por proteinas (capside). Nao possuem metabolismo proprio e so se replicam dentro de celulas hospedeiras.","resposta":""},
  {"id":"4023","tipo":"multipla","disciplina":"Biologia","tema":"Imunologia","subtema":"Sistema imune","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os anticorpos sao produzidos por:","alternativa_a":"Linfocitos B (plasmocitos)","alternativa_b":"Neutrofilos","alternativa_c":"Hematies (eritrocitos)","alternativa_d":"Plaquetas (trombocitos)","alternativa_e":"Linfocitos T citotoxicos","resposta_correta":"a","explicacao":"Os anticorpos (imunoglobulinas) sao proteinas produzidas pelos linfocitos B quando se diferenciam em plasmocitos apos reconhecerem um antigeno. Cada anticorpo e especifico para um antigeno. Os linfocitos T auxiliam na resposta imune adaptativa mas nao produzem anticorpos diretamente.","resposta":""},
  {"id":"4024","tipo":"multipla","disciplina":"Biologia","tema":"Botanica","subtema":"Reproducao das angiospermas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Na reproducao das angiospermas, a dupla fecundacao produz:","alternativa_a":"O embriao (2n) e o endosperma (3n)","alternativa_b":"Dois embriaos diploides","alternativa_c":"O gameta feminino e o masculino","alternativa_d":"A semente e o fruto","alternativa_e":"O polo e o exine do grao de polen","resposta_correta":"a","explicacao":"Nas angiospermas, o grao de polen libera dois nucleos espermaticos. Um se funde com a oosfera formando o zigoto (2n) que origina o embriao. O outro se funde com os dois nucleos polares do saco embrionario, formando o endosperma triplóide (3n), tecido de reserva nutritiva para o embriao.","resposta":""},
  {"id":"4025","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Imperialismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O neocolonialismo do seculo XIX diferenciou-se do colonialismo do seculo XVI-XVII principalmente por:","alternativa_a":"Ser motivado pela busca de materias-primas e mercados para a industria capitalista, e nao pelo mercantilismo","alternativa_b":"Nao envolver a escravizacao das populacoes colonizadas","alternativa_c":"Ser liderado por paises da America Latina","alternativa_d":"Ter carater humanitario e civilizatorio genuino","alternativa_e":"Nao causar conflitos militares entre as potencias","resposta_correta":"a","explicacao":"O neocolonialismo (imperialismo do seculo XIX) foi impulsionado pela Revolucao Industrial: as potencias industriais buscavam materias-primas (borracha, algodao, metais) e mercados consumidores para seus produtos. Ao contrario do mercantilismo colonial anterior, a logica era industrial e financeira. Resultou na partilha da Africa e da Asia entre as potencias europeias.","resposta":""},
  {"id":"4026","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Movimento Tenentista","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O tenentismo foi um movimento politico-militar brasileiro da decada de 1920 que buscava:","alternativa_a":"Combater a oligarquia agraria e modernizar o Estado brasileiro","alternativa_b":"Restaurar a monarquia de D. Pedro II","alternativa_c":"Implantar o socialismo no Brasil ao estilo da URSS","alternativa_d":"Garantir a autonomia dos estados na Republica Velha","alternativa_e":"Defender os interesses dos cafeicultores de Sao Paulo","resposta_correta":"a","explicacao":"O tenentismo foi um movimento de jovens oficiais do exercito (tenentes) que, na decada de 1920, se rebelaram contra a Republica Velha oligarquica. Defendiam: reforma politica, voto secreto, ensino publico, industrializacao e modernizacao do Estado. A Coluna Prestes (1924-1927) foi a expressao maxima do movimento.","resposta":""},
  {"id":"4027","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Getulismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A legislacao trabalhista implantada por Getulio Vargas (CLT, 1943) foi resultado de uma politica denominada:","alternativa_a":"Trabalhismo — concessao de direitos para cooptar e controlar a classe trabalhadora","alternativa_b":"Neoliberalismo — reducao da intervencao estatal","alternativa_c":"Socialismo — expropriacao dos meios de producao","alternativa_d":"Liberalismo economico — livre mercado e autonomia individual","alternativa_e":"Desenvolvimentismo — industrializacao sem participacao popular","resposta_correta":"a","explicacao":"Vargas implantou o trabalhismo: uma politica de concessao de direitos trabalhistas (salario minimo, ferias, INPS, CLT) que ao mesmo tempo cooptava e controlava a classe trabalhadora, impedindo a organizacao autonoma dos sindicatos (atrelados ao Estado). A imagem de 'pai dos pobres' consolidou a base de apoio popular de Vargas.","resposta":""},
  {"id":"4028","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Descolonizacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Conferencia de Bandung (1955) foi um marco da:","alternativa_a":"Descolonizacao e do Movimento dos Nao-Alinhados, reunindo paises afro-asiaticos","alternativa_b":"Formacao da OTAN e da alianca atlantica","alternativa_c":"Criacao da Comunidade Europeia","alternativa_d":"Divisao da Europa entre EUA e URSS","alternativa_e":"Partilha da Africa entre as potencias coloniais","resposta_correta":"a","explicacao":"A Conferencia de Bandung (Indonesia, 1955) reuniu 29 paises afro-asiaticos recentemente independentes. Propugnou a solidariedade entre os povos colonizados e a nao-alinhamento com os blocos da Guerra Fria (capitalismo e socialismo). Foi o embriao do Movimento dos Nao-Alinhados (1961) e do conceito de Terceiro Mundo.","resposta":""},
  {"id":"4029","tipo":"multipla","disciplina":"Geografia","tema":"Geopolitica","subtema":"Conflitos regionais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O conflito israelense-palestino tem origem principalmente em:","alternativa_a":"Disputas territoriais e religiosas pela criacao do Estado de Israel em 1948 no territorio da Palestina","alternativa_b":"Concorrencia pelo petroleo no Oriente Medio","alternativa_c":"Expansao do comunismo sovietico na regiao","alternativa_d":"Conflito entre sunitas e xiitas","alternativa_e":"Disputas por agua do Rio Jordao","resposta_correta":"a","explicacao":"O conflito israelense-palestino tem raizes no projeto sionista (criacao de um lar nacional judeu na Palestina) e na declaracao do Estado de Israel em 1948. A primeira guerra arabe-israelense e a Nakba (catastrofe em arabe) forcaram a fuga de centenas de milhares de palestinos. O conflito envolve disputas por territorio (Cisjordania, Gaza, Jerusalem) e autodeterminacao do povo palestino.","resposta":""},
  {"id":"4030","tipo":"multipla","disciplina":"Geografia","tema":"Recursos Naturais","subtema":"Desertificacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A desertificacao e o processo de:","alternativa_a":"Degradacao de terras em regioes aridas, semiaridas e subumidas secas devido a atividade humana e mudancas climaticas","alternativa_b":"Expansao natural de desertos por fenomenos geologicos","alternativa_c":"Urbanizacao acelerada de areas rurais","alternativa_d":"Poluicao de rios e lagos em regioes tropicais","alternativa_e":"Erosao costeira por acao das mares","resposta_correta":"a","explicacao":"A desertificacao e a degradacao de solos em regioes de clima seco causada por uso excessivo da terra (pecuaria intensiva, agricultura inadequada), desmatamento e mudancas climaticas. Afeta principalmente Africa subsaariana, norte do Brasil (Semiarido), sul da Europa e Asia Central. E um dos maiores problemas ambientais globais.","resposta":""},
  {"id":"4031","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Linguistica","subtema":"Funcoes da linguagem","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A funcao da linguagem que se centra na mensagem em si mesma, valorizando a forma da expressao, e a:","alternativa_a":"Poetica","alternativa_b":"Referencial","alternativa_c":"Apelativa","alternativa_d":"Fática","alternativa_e":"Metalinguistica","resposta_correta":"a","explicacao":"Roman Jakobson identificou seis funcoes da linguagem. A funcao poetica centra-se na mensagem — na forma como as palavras sao combinadas, no ritmo, na sonoridade, nas metaforas. E predominante em poesias, mas ocorre tambem em publicidade, musica e literatura. Nao se limita a poesia: qualquer uso estetico da linguagem e poetico.","resposta":""},
  {"id":"4032","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Colocacao pronominal","diculdade":"Medio","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em frase interrogativa, a colocacao pronominal correta e:","alternativa_a":"Proclise — pronome antes do verbo","alternativa_b":"Enclise — pronome depois do verbo","alternativa_c":"Mesoclise — pronome no meio do verbo","alternativa_d":"Pode ser qualquer posicao livremente","alternativa_e":"O pronome nao pode ser usado em perguntas","resposta_correta":"a","explicacao":"Em frases interrogativas (com pronomes/adverbios interrogativos), usa-se a proclise: 'Quem te disse isso?', 'Quando me avisaras?'. Da mesma forma, em frases negativas, com subordinativas e com certas palavras atrativas (ja, sempre, tambem, etc.), usa-se proclise. A mesoclise ocorre com verbos no futuro do indicativo em frases sem atrativos.","resposta":""},
  {"id":"4033","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Simbolismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Cruz e Sousa, principal nome do Simbolismo brasileiro, ficou conhecido como 'Cisne Negro' por ser:","alternativa_a":"Um poeta negro que subverteu o racismo da epoca ao atingir o topo da arte literaria","alternativa_b":"Autor de obras com temas negros e animais selvagens","alternativa_c":"Seguidor da tradicao africana oral","alternativa_d":"Critico do Romantismo e do Parnasianismo","alternativa_e":"O primeiro poeta a escrever sobre a escravidao","resposta_correta":"a","explicacao":"Joao da Cruz e Sousa (1861-1898) era filho de escravizados alforriados. Tornou-se o maior poeta simbolista brasileiro, com obras como 'Missal' e 'Broqueis'. O apelido 'Cisne Negro' carrega duplo sentido: a raridade do cisne negro (algo improvavel) e sua condicao de homem negro que alcanou o auge da producao literaria numa sociedade racista pos-escravocrata.","resposta":""},
  {"id":"4034","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Parnasianismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Parnasianismo brasileiro, influenciado pelo movimento frances, caracterizava-se principalmente por:","alternativa_a":"Culto a forma perfeita, objetividade, impessoalidade e uso de vocabulario erudito","alternativa_b":"Subjetivismo exacerbado e idealizacao da mulher amada","alternativa_c":"Linguagem coloquial e temas do cotidiano urbano","alternativa_d":"Misticismo e valorização do inconsciente","alternativa_e":"Preocupacao social e regionalismo nordestino","resposta_correta":"a","explicacao":"O Parnasianismo (fin do seculo XIX) prezava pela 'arte pela arte': forma impecavel, versificacao rigorosa (metrificacao, rima perfeita), objetividade, impessoalidade e vocabulario erudito. No Brasil, seus representantes sao Olavo Bilac, Alberto de Oliveira e Raimundo Correa (a 'trindade parnasiana').","resposta":""},
  {"id":"4035","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Democracia","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A democracia ateniense do seculo V a.C. diferia da democracia moderna principalmente porque:","alternativa_a":"Era democracia direta e excluia mulheres, escravizados e estrangeiros","alternativa_b":"Era representativa e incluia todos os cidadaos sem distincao","alternativa_c":"Permitia a participacao de todos os habitantes da polis","alternativa_d":"Era uma teocracia disfarçada de democracia","alternativa_e":"Concentrava o poder nas maos de um unico magistrado eleito","resposta_correta":"a","explicacao":"A democracia ateniense (de Clístenes e Pericles) era direta: os cidadaos participavam pessoalmente das decisoes na ekklesia (assembleia). Porem, cidadaos eram apenas homens adultos livres atenienses — mulheres, escravizados (base da economia) e metecos (estrangeiros residentes) eram excluidos. A democracia moderna e representativa e formalmente universal.","resposta":""},
  {"id":"4036","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Mente","subtema":"Problema mente-corpo","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O dualismo cartesiano de Descartes propoe que:","alternativa_a":"Mente (res cogitans) e corpo (res extensa) sao substancias completamente distintas","alternativa_b":"Mente e corpo sao uma unica substancia material","alternativa_c":"A mente e apenas uma funcao do cerebro","alternativa_d":"Nao existe mente separada do corpo","alternativa_e":"Corpo e mente sao manifestacoes do mesmo espirito divino","resposta_correta":"a","explicacao":"Descartes distinguiu duas substancias fundamentais: res cogitans (coisa pensante, a mente/alma — imaterial, indivisivel) e res extensa (coisa extensa, o corpo/materia — espacial, divisivel). O problema do dualismo cartesiano e explicar como essas substancias radicalmente diferentes interagem. Descartes propôs a glandula pineal como ponto de interacao.","resposta":""},
  {"id":"4037","tipo":"multipla","disciplina":"Filosofia","tema":"Etica","subtema":"Etica deontologica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O imperativo categorico de Kant determina que se deve agir apenas segundo uma maxima que possa ser:","alternativa_a":"Universalizada como lei para todos os seres racionais","alternativa_b":"Aprovada pelo governo","alternativa_c":"Benfica para a maioria das pessoas","alternativa_d":"Compativel com as tradicoes culturais locais","alternativa_e":"Derivada da revelacao religiosa","resposta_correta":"a","explicacao":"O imperativo categorico kantiano (formula da universalizabilidade): 'Age apenas segundo a maxima pela qual podes ao mesmo tempo querer que ela se torne uma lei universal.' E um principio formal da razao pratica: uma acao e moral se sua maxima puder ser universalizada sem contradicao. Por exemplo: mentir nao pode ser universalizado pois destruiria a propria instituicao da linguagem.","resposta":""},
  {"id":"4038","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Religiao","subtema":"Religiao em Weber","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Na obra 'A Etica Protestante e o Espirito do Capitalismo', Weber argumenta que:","alternativa_a":"A etica calvinista do trabalho como vocacao e a predestinacao contribuiram para o desenvolvimento do capitalismo","alternativa_b":"O catolicismo foi o principal fator de desenvolvimento economico europeu","alternativa_c":"A religiao e um reflexo das relacoes economicas de producao","alternativa_d":"O capitalismo destruiu os valores religiosos tradicionais","alternativa_e":"O islamismo foi a religiao que mais favoreceu o capitalismo","resposta_correta":"a","explicacao":"Weber argumenta que a etica calvinista — especialmente a doutrina da predestinacao (o individuo nao sabe se esta salvo) — levou os protestantes a buscarem sinais de eleicao divina no sucesso economico. O trabalho como vocacao (Beruf), a austeridade e a acumulacao de capital (sem esbanjamento) criaram uma 'afinidade eletiva' com o espirito do capitalismo moderno.","resposta":""},
  {"id":"4039","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Educacao","subtema":"Capital cultural","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Pierre Bourdieu desenvolve o conceito de 'capital cultural' para explicar:","alternativa_a":"Como o conhecimento, os diplomas e os habitos culturais reproduzem as desigualdades sociais","alternativa_b":"O valor monetario da producao cultural de um pais","alternativa_c":"O sistema de financiamento das artes pelo Estado","alternativa_d":"A influencia da cultura popular na alta cultura","alternativa_e":"A democratizacao do acesso ao ensino superior","resposta_correta":"a","explicacao":"Para Bourdieu, capital cultural e um conjunto de recursos culturais (conhecimentos, diplomas, habitos, gostos) que conferem vantagens sociais. Existe em tres formas: incorporado (habitus, disposicoes interiorizadas), objetivado (livros, obras de arte) e institucionalizado (titulos e diplomas). A escola, ao valorizar a cultura das classes dominantes, reproduz e legitima as desigualdades sociais.","resposta":""},
  {"id":"4040","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia do Genero","subtema":"Feminismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O conceito de 'patriarcado' nas teorias feministas refere-se a:","alternativa_a":"Sistema de dominacao masculina que permeia as relacoes sociais, politicas e economicas","alternativa_b":"Governo exercido pelo pai na familia nuclear tradicional","alternativa_c":"A heranca juridica do direito romano sobre a familia","alternativa_d":"Superioridade biologica dos homens sobre as mulheres","alternativa_e":"Tradicao religiosa de obediencia ao pai de familia","resposta_correta":"a","explicacao":"O patriarcado, nas teorias feministas, e um sistema social de dominacao e opressao masculina que se manifesta em multiplas esferas: domestica (divisao sexual do trabalho), politica (sub-representacao feminina), economica (diferenca salarial), cultural (objetificacao da mulher) e simbolica (normas de genero). Autoras como Simone de Beauvoir, Betty Friedan e Judith Butler contribuiram para teorizar essas questoes.","resposta":""},
  {"id":"4041","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Logaritmos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O valor de log2(64) e:","alternativa_a":"6","alternativa_b":"4","alternativa_c":"8","alternativa_d":"32","alternativa_e":"3","resposta_correta":"a","explicacao":"log2(64) = x => 2^x = 64 = 2^6, logo x = 6.","resposta":""},
  {"id":"4042","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Volume do cubo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um cubo tem aresta de 3 cm. Seu volume e:","alternativa_a":"27 cm3","alternativa_b":"9 cm3","alternativa_c":"54 cm3","alternativa_d":"81 cm3","alternativa_e":"18 cm3","resposta_correta":"a","explicacao":"Volume do cubo = a3 = 3^3 = 27 cm3.","resposta":""},
  {"id":"4043","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Area do circulo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um circulo tem raio de 5 cm. Sua area e (use pi = 3,14):","alternativa_a":"78,5 cm2","alternativa_b":"31,4 cm2","alternativa_c":"25 cm2","alternativa_d":"157 cm2","alternativa_e":"15,7 cm2","resposta_correta":"a","explicacao":"A = pi * r2 = 3,14 * 25 = 78,5 cm2.","resposta":""},
  {"id":"4044","tipo":"multipla","disciplina":"Fisica","tema":"Acustica","subtema":"Qualidades do som","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A intensidade do som e percebida como:","alternativa_a":"Volume (loudness) — mais alto ou mais baixo","alternativa_b":"Tom — grave ou agudo","alternativa_c":"Timbre — qualidade do som","alternativa_d":"Eco","alternativa_e":"Ressonancia","resposta_correta":"a","explicacao":"As tres qualidades fisiologicas do som: intensidade (volume/loudness — relacionada a amplitude da onda, medida em dB), altura/tom (grave ou agudo — relacionada a frequencia) e timbre (qualidade que distingue dois sons de mesma intensidade e frequencia, determinada pelos harmonicos).","resposta":""},
  {"id":"4045","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Torque","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma forca de 10 N e aplicada perpendicularmente a uma barra rigida a 0,5 m do eixo de rotacao. O torque produzido e:","alternativa_a":"5 N.m","alternativa_b":"0,5 N.m","alternativa_c":"10 N.m","alternativa_d":"20 N.m","alternativa_e":"50 N.m","resposta_correta":"a","explicacao":"Torque = Forca x braco de alavanca = F * d * sen(90) = 10 * 0,5 * 1 = 5 N.m.","resposta":""},
  {"id":"4046","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Forças intermoleculares","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A alta temperatura de ebulicao da agua (100 graus C) em relacao a outras moleculas de tamanho similar deve-se principalmente a:","alternativa_a":"Ligacoes de hidrogenio entre as moleculas de H2O","alternativa_b":"Ligacoes covalentes fortes dentro da molecula","alternativa_c":"Forcas de London (dispersao)","alternativa_d":"Forças ionicas entre H+ e OH-","alternativa_e":"Alta massa molecular da agua","resposta_correta":"a","explicacao":"A agua forma ligacoes de hidrogenio — interacoes intermoleculares fortes entre o H de uma molecula e o O eletronegativo de outra. Por isso, precisa de mais energia (maior temperatura) para romper essas interacoes e passar para o estado gasoso. As ligacoes de H sao muito mais fortes que as forcas de Van der Waals (London e dipolo-dipolo).","resposta":""},
  {"id":"4047","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Radioatividade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O carbono-14 (C-14) e utilizado em datacao de materiais organicos porque:","alternativa_a":"Tem meia-vida conhecida (~5730 anos) e e incorporado pelos seres vivos enquanto vivos","alternativa_b":"E o isotopo mais abundante do carbono","alternativa_c":"Emite radiacoes que preservam os materiais antigos","alternativa_d":"Tem numero atomico diferente do carbono-12","alternativa_e":"E produzido por reacoes quimicas nos organismos vivos","resposta_correta":"a","explicacao":"O C-14 e produzido na atmosfera por radiacoes cosmicas e incorporado pelos organismos vivos (via CO2) enquanto vivem. Apos a morte, o C-14 decai com meia-vida de ~5730 anos sem reposicao. Medindo a proporcao de C-14 restante, calcula-se o tempo desde a morte do organismo. Funciona para materiais de ate ~50.000 anos.","resposta":""},
  {"id":"4048","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Relacoes ecologicas","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A relacao entre o peixe-palhaco e a anemona-do-mar, onde ambos se beneficiam, e chamada de:","alternativa_a":"Mutualismo","alternativa_b":"Comensalismo","alternativa_c":"Parasitismo","alternativa_d":"Competicao","alternativa_e":"Predacao","resposta_correta":"a","explicacao":"O mutualismo e uma relacao interespecifica harmonica (sem dano) em que ambas as especies se beneficiam. O peixe-palhaco vive protegido entre os tentaculos da anemona (que e venenosa para outros peixes) e em troca limpa a anemona e afasta predadores. Outros exemplos: bacterias intestinais humanas, fungos e algas nos liquens.","resposta":""},
  {"id":"4049","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema endocrino","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A insulina, hormonio que regula a glicemia, e produzida por:","alternativa_a":"Celulas beta das ilhotas de Langerhans no pancreas","alternativa_b":"Glandula tireoide","alternativa_c":"Glandula adrenal (suprarrenal)","alternativa_d":"Hipofise","alternativa_e":"Figado","resposta_correta":"a","explicacao":"A insulina e produzida pelas celulas beta das ilhotas de Langerhans no pancreas. E liberada quando a glicemia sobe (apos refeicao), facilitando a captacao de glicose pelas celulas e seu armazenamento como glicogenio. A deficiencia de insulina ou resistencia a ela causa diabetes mellitus.","resposta":""},
  {"id":"4050","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Golpe Militar 1964","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O golpe militar de 1964 que depôs Joao Goulart foi justificado pelos militares como:","alternativa_a":"Necessario para evitar uma 'ameaca comunista' e defender a democracia","alternativa_b":"Uma resposta a corrupcao do governo democratico de Goulart","alternativa_c":"Uma revolucao popular de base","alternativa_d":"Um mandato da ONU para restaurar a ordem","alternativa_e":"Uma reacao a invasao de tropas estrangeiras","resposta_correta":"a","explicacao":"O golpe de 31/03-01/04/1964 foi justificado pelos militares e pela UDN como necessario para evitar uma 'comunizacao' do Brasil, diante das reformas de base propostas por Goulart (reforma agraria, educacional, tributaria). Na pratica, contou com apoio dos EUA (interesse geopolitico na Guerra Fria) e de setores conservadores da sociedade. Inaugurou 21 anos de ditadura.","resposta":""},
  {"id":"4051","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Redemocratizacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A Constituicao Federal Brasileira vigente foi promulgada em:","alternativa_a":"5 de outubro de 1988","alternativa_b":"15 de novembro de 1889","alternativa_c":"7 de setembro de 1822","alternativa_d":"5 de outubro de 1969","alternativa_e":"15 de janeiro de 1985","resposta_correta":"a","explicacao":"A Constituicao Federal de 1988, conhecida como 'Constituicao Cidada' (expressao de Ulysses Guimaraes), foi promulgada em 5 de outubro de 1988. Marcou a transicao definitiva para a democracia apos a ditadura militar, garantindo amplos direitos fundamentais. E a sétima Constituicao brasileira.","resposta":""},
  {"id":"4052","tipo":"multipla","disciplina":"Geografia","tema":"Populacao","subtema":"Migracao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A migracao pendular nas metropoles brasileiras refere-se ao:","alternativa_a":"Deslocamento diario entre o local de residencia (periferia) e o local de trabalho (centro)","alternativa_b":"Fluxo de migrantes do campo para a cidade","alternativa_c":"Retorno de migrantes ao seu local de origem","alternativa_d":"Migracao de brasileiros para outros paises","alternativa_e":"Movimentacao sazonal de trabalhadores rurais","resposta_correta":"a","explicacao":"A migracao pendular (ou mobilidade pendular) e o deslocamento cotidiano de trabalhadores entre periferia (onde moram por nao poderem arcar com o custo de vida central) e areas centrais (onde trabalham). E um indicador de segregacao socioespacional e problemas de transporte urbano. Em cidades como Sao Paulo, milhoes de pessoas fazem esse trajeto diariamente.","resposta":""},
  {"id":"4053","tipo":"multipla","disciplina":"Geografia","tema":"Industria","subtema":"Desindustrializacao","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O processo de desindustrializacao no Brasil a partir dos anos 1990 foi causado principalmente por:","alternativa_a":"Abertura comercial, valorizacao cambial e competicao de paises com custo de producao menor","alternativa_b":"Escassez de mao de obra qualificada","alternativa_c":"Politica deliberada de transicao para economia de servicos","alternativa_d":"Esgotamento das reservas de materias-primas industriais","alternativa_e":"Restricoes ambientais as industrias poluidoras","resposta_correta":"a","explicacao":"A desindustrializacao brasileira acelerou-se na decada de 1990 com: abertura comercial do governo Collor (importacoes mais baratas que producao nacional), valorizacao do real (plano Real), e competicao de produtos chineses e asiaticos de baixo custo. O setor industrial perdeu participacao no PIB, com terceirizacao e substituicao por importacoes, sem uma transicao para industrias de maior valor agregado.","resposta":""},
  {"id":"4054","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Textualidade","subtema":"Coesao textual","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os conectivos 'portanto', 'logo' e 'por conseguinte' estabelecem entre as oracoes uma relacao de:","alternativa_a":"Conclusao","alternativa_b":"Concessao","alternativa_c":"Oposicao","alternativa_d":"Causa","alternativa_e":"Condicao","resposta_correta":"a","explicacao":"Os conectivos 'portanto', 'logo', 'por conseguinte', 'assim', 'dessa forma', 'entao' estabelecem relacao de conclusao ou consequencia. Conectivos de concessao: 'embora', 'apesar de', 'ainda que'. De oposicao: 'mas', 'porem', 'todavia'. De causa: 'porque', 'ja que', 'pois'. De condicao: 'se', 'caso'.","resposta":""},
  {"id":"4055","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Vozes verbais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em 'O documento foi assinado pelo presidente', o verbo esta na voz:","alternativa_a":"Passiva analitica","alternativa_b":"Ativa","alternativa_c":"Reflexiva","alternativa_d":"Passiva sintetica","alternativa_e":"Media","resposta_correta":"a","explicacao":"A voz passiva analitica e formada por verbo auxiliar (ser/estar/ficar) + participio do verbo principal. 'Foi assinado' = auxiliar 'foi' (ser) + participio 'assinado'. Na voz ativa seria: 'O presidente assinou o documento.' Na passiva sintetica usa-se o pronome 'se': 'Assinou-se o documento.'","resposta":""},
  {"id":"4056","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Ciencia","subtema":"Estrutura das revolucoes","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Thomas Kuhn, em 'A Estrutura das Revolucoes Cientificas', introduziu o conceito de:","alternativa_a":"Paradigma — modelo cientifico dominante que orienta a pesquisa em um periodo","alternativa_b":"Falsificabilidade como criterio cientifico","alternativa_c":"Programa de pesquisa cientifico","alternativa_d":"Anarquismo metodologico","alternativa_e":"Positivismo logico","resposta_correta":"a","explicacao":"Kuhn argumentou que a ciencia progride por revolucoes, nao por acumulacao linear. Um paradigma e a constelacao de crencas, valores e tecnicas compartilhada por uma comunidade cientifica. Durante a 'ciencia normal', os cientistas resolvem quebra-cabecas dentro do paradigma. Quando anomalias se acumulam, ocorre uma 'crise' e eventualmente uma 'revolucao cientifica' substitui o paradigma (ex: de Geocentrico para Heliocentrico).","resposta":""},
  {"id":"4057","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia Classica","subtema":"Tipos de dominacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A dominacao carismatica, segundo Weber, baseia-se em:","alternativa_a":"Qualidades extraordinarias atribuidas a um lider por seus seguidores","alternativa_b":"Normas legais e racionais impessoais","alternativa_c":"Tradicoes e costumes imutaveis","alternativa_d":"Controle economico dos meios de producao","alternativa_e":"Forca militar e coercao","resposta_correta":"a","explicacao":"A dominacao carismatica e um dos tres tipos weberianos de autoridade legitima. Baseia-se em qualidades excepcionais percebidas nos lideres (santos, profetas, herois, demagogos). E instavel, pois depende de provas continuas de excepcionalidade. Quando o carisma se institucionaliza (rotinizacao do carisma), transforma-se em dominacao tradicional ou legal-racional.","resposta":""},
  {"id":"4058","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Cultura","subtema":"Identidade cultural","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Stuart Hall argumenta que as identidades culturais na pos-modernidade sao:","alternativa_a":"Fragmentadas, hibridas e em constante transformacao, nao mais fixas ou essenciais","alternativa_b":"Fixas, essenciais e determinadas pelo nascimento","alternativa_c":"Uniformizadas pela globalizacao cultural","alternativa_d":"Exclusivamente definidas pela classe social","alternativa_e":"Determinadas pelo Estado nacional","resposta_correta":"a","explicacao":"Stuart Hall, em 'A Identidade Cultural na Pos-Modernidade', argumenta que o sujeito moderno tinha uma identidade unificada e estavel, mas na pos-modernidade as identidades tornam-se multiplas, contraditorias, hibridas e contingentes. A globalizacao, a migracao e a hibridizacao cultural fragmentam as identidades nacionais e etnicas, criando novas formas de identificacao.","resposta":""},
]

